<template><div><h2>🏫 校园代理</h2><el-button type="primary" size="small" @click="show=true;reset()">+ 添加代理</el-button><el-table :data="list" stripe size="small" style="margin-top:8px"><el-table-column prop="name" label="姓名"/><el-table-column prop="phone" label="电话"/><el-table-column prop="campus" label="校区"/><el-table-column label="等级"><template #default="{row}"><el-tag :type="row.level==='金牌'?'warning':row.level==='银牌'?'info':''" size="small">{{ row.level }}</el-tag></template></el-table-column><el-table-column label="佣金率"><template #default="{row}">{{ (row.commission_rate*100).toFixed(0) }}%</template></el-table-column><el-table-column prop="total_earned" label="已赚"/></el-table><el-dialog v-model="show" title="添加代理" width="360px"><el-form label-width="70px"><el-form-item label="姓名"><el-input v-model="f.name"/></el-form-item><el-form-item label="电话"><el-input v-model="f.phone"/></el-form-item><el-form-item label="校区"><el-input v-model="f.campus"/></el-form-item><el-form-item label="等级"><el-select v-model="f.level" style="width:100%"><el-option label="初级" value="初级"/><el-option label="银牌" value="银牌"/><el-option label="金牌" value="金牌"/></el-select></el-form-item><el-form-item label="佣金率"><el-input-number v-model="f.commissionRate" :min="0.01" :max="0.3" :step="0.01" style="width:100%"/></el-form-item></el-form><template #footer><el-button @click="show=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import {ref,reactive,onMounted} from 'vue';import request from '@/utils/request';import {ElMessage} from 'element-plus';const list=ref([]);const show=ref(false);const f=reactive({name:'',phone:'',campus:'',level:'初级',commissionRate:0.05});function reset(){Object.assign(f,{name:'',phone:'',campus:'',level:'初级',commissionRate:0.05})}async function fetch(){try{list.value=await request.get('/campus-agents')||[]}catch{}}async function save(){try{await request.post('/campus-agents',f);show.value=false;fetch();ElMessage.success('已添加')}catch{}}onMounted(fetch)</script>
